96. function detectLoopingBehavior() {
97.   if (confusionMetrics.recentMessages.length < 3) return false;
98.   let similarPairs = 0;
99.   for (let i = confusionMetrics.recentMessages.length - 1; i > 0; i--) {
100.     if (
101.       calculateSimilarity(
102.         confusionMetrics.recentMessages[i],
103.         confusionMetrics.recentMessages[i - 1],
